var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크윽…… 크으으…….</color>","JPN":"<color=#ff3636>くっ……くうぅ……</color>","ENG":"<color=#ff3636>Krr... Khhhhkkk...</color>","TWN":"<color=#ff3636>呃呃……呃呃呃……</color>"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"조금이라도 더…… <color=#ff3636>해치워야 해……</color>","JPN":"もっと……<color=#ff3636>やらなければ……</color>","ENG":"I must... <color=#ff3636>get rid of more of them...</color>","TWN":"必須再……<color=#ff3636>多除掉一些……</color>"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"무분별한 증오가 휘몰아친다.","JPN":"無分別な憎しみが押し寄せてくる。","ENG":"A vicious hatred is raging.","TWN":"一種盲目的厭惡感湧上心頭。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"이성은 거센 파도에 휩쓸리는 나뭇가지와 같다.","JPN":"理性は荒い波に流される木の枝のようだ。","ENG":"Reason feels like a branch being swept away by a powerful wave.","TWN":"理性仿佛是被巨浪卷走的樹枝。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"나는…… 이 나뭇가지가 부러질 때까지, 얼마나 많은 파도를 견뎌낼 수 있을까.","JPN":"私は……この枝が折れるまで、どれだけ波に耐えられるだろうか。","ENG":"Until that branch breaks... I wonder how many more waves I can endure.","TWN":"我……在這根樹枝折斷之前，究竟能撐過多少巨浪。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님을…… 방해하는 것들은…… <color=#ff3636>전부……</color>","JPN":"当主を……邪魔するもの……<color=#ff3636>全て……</color>","ENG":"<color=#ff3636>Anything...</color> that tries to interfere... with Lady Nanahara...","TWN":"妨礙……堂主的……<color=#ff3636>全都……</color>"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>……벤다!</color>","JPN":"<color=#ff3636>……斬る！</color>","ENG":"<color=#ff3636>……I shall cut!</color>","TWN":"<color=#ff3636>……要斬殺！</color>"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라 치후유……","JPN":"七原千冬……","ENG":"Nanahara Chifuyu...","TWN":"七原千冬……"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신의 피에 먹히지 않은 채로, 저 많은 역귀들을 단숨에 해치우다니……","JPN":"疫病神の血に飲まれず、あの数の疫鬼を一気に倒すとは……","ENG":"You defeated all of the Plagued Ghosts... and did so without being consumed by the blood of the Plague God...","TWN":"居然在沒被瘟神血液吞噬的狀態下，一口氣除掉那麼多疫鬼……"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만…… 완전히 잠식되는 것은 시간문제다.","JPN":"しかし……完全に侵食されるのも時間の問題じゃ。","ENG":"However... It is only a matter of time before it completely corrupts you.","TWN":"不過……被徹底吞噬只是時間問題。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"굉장하군. 역신의 피에 잠식되고도 그릇의 형질을 유지하다니.","JPN":"素晴らしい。疫病神の血に飲まれても器の形質を維持するとは。","ENG":"Astounding. The vessel is still maintaining her form after the blood has spread all throughout her.","TWN":"真厲害，被瘟神血液侵蝕後竟然還能保持器皿的形質。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"네놈. 대체 왜 네 부하놈들까지 희생시켜가며 이런 짓을 벌이는 거냐?","JPN":"貴様。なぜ部下たちを犠牲にしてまでこんな真似をするのじゃ？","ENG":"You...! What are you trying to accomplish by sacrificing your men?!","TWN":"你這傢伙，究竟為什麼不惜犧牲自己的部下，也要做這種事？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"신의 영혼이 찾아갈 그릇을 완성하기 위해서라오.","JPN":"神の魂が宿る器を完成させるためだ。","ENG":"To find and complete a vessel for god's soul to rest.","TWN":"因為要完成能夠承受神靈魂的器皿。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이 과정에선 무엇보다 자신의 의지로 피를 받아들이게 하는 것이 중요했지.","JPN":"そのためには自身の意志により血を受け入れさせなければならなかった。","ENG":"But the most important process was to allow the vessel to accept the blood on her own.","TWN":"這個過程中最重要的是靠自己的意志去接受血液。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그렇다는 건…….","JPN":"ということは……","ENG":"Then that means...","TWN":"也就是說……"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"애당초 나나하라 당주가 아니라 호위를 노렸다는 건가?","JPN":"最初から七原当主ではなく、護衛を狙っていたということか？","ENG":"You were after Chifuyu and not Lady Nanahara from the first?","TWN":"你打從一開始盯上的就是護衛而不是七原堂主？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};